// Agrupa por grupo interno -> 1 mensagem/grupo. Sem matches => sem output (noop).
const items = $input.all().map((i) => i.json)
if (items.length === 0) return []
const fmt = (n) => Number(n).toLocaleString('pt-BR')
const byGroup = {}
for (const j of items) {
  const key = j.grupo_interno_jid
  if (!byGroup[key]) byGroup[key] = { grupo_interno_jid: key, instance: j.instance, linhas: [] }
  byGroup[key].linhas.push(
    `\u2022 ${j.cliente_nome} \u2014 ${fmt(j.saldo)} ${j.origem} \u2192 ~${fmt(j.resultado)} ${j.destino} (${fmt(j.bonus_numeric)}%)`
  )
}
return Object.values(byGroup).map((g) => ({
  json: {
    grupo_interno_jid: g.grupo_interno_jid,
    instance: g.instance,
    mensagem: `*\ud83d\udcca Promoções que batem com carteiras (24h)*\n\n` + g.linhas.join('\n'),
  },
}))
